document.addEventListener("DOMContentLoaded", function() {
    
    const filterForm = document.querySelector('#changelist-search');
    
    if (filterForm) {
        // --- 1. MASTER SEARCH BUTTON LOGIC ---
        // Find the search button generated by the rangefilter package
        const rangeSearchBtn = filterForm.querySelector('.admindatefilter input[type="submit"], .admindatefilter button[type="submit"], .admindatefilter .button.default');
        
        if (rangeSearchBtn) {
            rangeSearchBtn.addEventListener('click', function(e) {
                e.preventDefault(); // Stop the default submission
                
                let params = new URLSearchParams();
                
                // Grab the selected values from the Guest and Status dropdowns
                filterForm.querySelectorAll('select').forEach(function(select) {
                    if (select.value && select.value !== '') {
                        params.set(select.name, select.value);
                    }
                });
                
                // Grab the typed values from the Date Range text boxes
                filterForm.querySelectorAll('input[type="text"], input[type="date"]').forEach(function(input) {
                    if (input.name && input.value) {
                        params.set(input.name, input.value);
                    }
                });
                
                // Reload the page applying all the filters
                window.location.href = window.location.pathname + '?' + params.toString();
            });
        }
    }

    // --- 2. RESET BUTTON LOGIC ---
    // Target the reset button inside the date filter
    const resetBtn = document.querySelector('.admindatefilter a, .admindatefilter input[type="reset"]');
    
    if (resetBtn) {
        resetBtn.addEventListener('click', function(e) {
            e.preventDefault(); // Stop the link from redirecting
            
            // Forcefully empty the date boxes
            document.querySelectorAll('.admindatefilter input[type="text"], .admindatefilter input[type="date"]').forEach(function(input) {
                input.value = '';
            });
        });
    }
});